#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int dp[8][1000000001];

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, A, B;
        scanf("%d %d %d", &N, &A, &B);
        int Li, Ri;
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &Li, &Ri);
        }
        // Initialize DP table
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= 1000000000; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j <= 1000000000; j++) {
                for (int k = Li; k <= Ri; k++) {
                    if (j - k >= 0) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][j - k]) % MOD;
                    }
                }
            }
        }
        int ans = 0;
        for (int i = A; i <= B; i++) {
            ans = (ans + dp[N][i]) % MOD;
        }
        printf("%d\n", ans);
    }
    return 0;
}

