const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextIntArray() {
    return lines[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, A, B] = nextIntArray();
    let intervals = [];
    for (let i = 0; i < N; i++) {
        intervals.push(nextIntArray());
    }
    let dp = Array(N + 1).fill(0).map(() => Array(1000000001).fill(0));
    dp[0][0] = 1;
    for (let i = 1; i <= N; i++) {
        for (let j = 0; j <= 1000000000; j++) {
            for (let k = intervals[i - 1][0]; k <= intervals[i - 1][1]; k++) {
                if (j - k >= 0) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - k]) % MOD;
                }
            }
        }
    }
    let ans = 0;
    for (let i = A; i <= B; i++) {
        ans = (ans + dp[N][i]) % MOD;
    }
